  --pui-color-primary: #4f46e5;
  --pui-color-primary-hover: #4338ca;
  --pui-radius-md: 0.5rem;
}`;

  protected readonly playgroundVariant = signal<PuiButtonVariant>('primary');
  protected readonly playgroundSize = signal<PuiButtonSize>('md');
