  });

  protected readonly tabs: readonly PuiDocsTab[] = [
    { label: 'Overview', route: ['/docs/components/tabs/overview'] },
    { label: 'Variants', route: ['/docs/components/tabs/variants'] },
    { label: 'Examples', route: ['/docs/components/tabs/examples'] },
